// Pega todos os itens (linhas do banco de dados) que chegaram
const items = $input.all();

// VERIFICAÇÃO 1: Se a lista de itens estiver vazia, 
// retorna um histórico vazio e encerra a execução deste nó.
if (items.length === 0) {
  return [{ json: { historico_recente: '' } }];
}

// Se houver itens, continua o processo de formatação...
let historicoFormatado = '';

// Inverte a ordem para mostrar do mais antigo para o mais novo
for (const item of items.reverse()) {

  // VERIFICAÇÃO 2: Garante que o item tem a estrutura esperada antes de usá-lo
  if (item.json && item.json.message && item.json.message.type && item.json.message.content) {
    const msg = item.json.message;
    const tipo = msg.type;
    const conteudo = msg.content;

    if (tipo === 'human') {
      historicoFormatado += `Humano: ${conteudo}\n`;
    } else if (tipo === 'ai') {
      historicoFormatado += `Assistente: ${conteudo}\n`;
    }
  }
  // Se um item não tiver a estrutura correta, ele será simplesmente ignorado.
}

// Retorna o objeto com o histórico pronto para ser usado no prompt
return [{ json: { historico_recente: historicoFormatado } }];

const ultima_mensagem_da_fila = $input.last()
const mensagem_do_workflow = $('Info').first()

if (ultima_mensagem_da_fila.json.id_mensagem !== mensagem_do_workflow.json.id_mensagem) {
  // Mensagem encavalada, para o workflow
  return [];
}

// Pass-through da fila de mensagens
return $input.all();

// Pega o texto do nó anterior
const textoCompleto = $('Separando dados output').first().json.resposta_para_usuario;



// $('Merge').first().json.text
// $('Formatar texto').first().json.text

// Nosso novo separador: a quebra de linha dupla.
const separador = '\n\n';

// Se o texto não existe ou não contém o separador, envia como uma mensagem única.
if (!textoCompleto || !textoCompleto.includes(separador)) {
  return [{ json: { text: textoCompleto || '' } }];
}

// 1. Divide o texto em um array usando a quebra de linha dupla
const partesDoTexto = textoCompleto.split(separador);

// 2. Transforma cada parte do texto em um item do n8n
const itensSaida = partesDoTexto.map(parte => {
  // Ignora partes que ficarem vazias 
  if (parte.trim() === '') {
    return null;
  }

  // Cria o objeto no formato que o n8n espera
  return {
    json: {
      text: parte.trim() // .trim() remove espaços/linhas em branco antes e depois
    }
  };
}).filter(item => item !== null); // 3. Remove os itens que ficaram nulos

// Retorna a lista de itens, prontos para o fluxo
return itensSaida;

// Pega a nova mensagem do usuário, que está no nó 'Info'
const novaMensagem = $('Info').first().json.mensagem;

// Pega o resultado da busca no Supabase
const resultadoDb = $input.all();

// Pega o resumo anterior. Se não existir (primeira mensagem), usa "Nenhum".
const resumoAnterior = resultadoDb[0]?.json.historico_resumido || 'Nenhum';

// Monta o prompt combinado que a IA vai receber
const promptCombinado = `Resumo da conversa até agora:\n${resumoAnterior}\n\nNova mensagem do usuário:\n${novaMensagem}`;

// Retorna o prompt combinado para ser usado pelo Agente
return [{ json: { prompt_para_agente: promptCombinado } }];

