// Pega a data e hora em que o workflow está rodando
const hoje = new Date();

// Define o horário para o início do dia de HOJE (00:00:00)
const inicioDoDia = new Date(hoje);
inicioDoDia.setHours(0, 0, 0, 0);

// Define o horário para o fim do dia de HOJE (23:59:59)
const fimDoDia = new Date(hoje);
fimDoDia.setHours(23, 59, 59, 999);

// Retorna as datas de início e fim no formato ISO, que é o padrão que o Google Calendar espera.
return [{
  json: {
    inicioDoDiaISO: inicioDoDia.toISOString(),
    fimDoDiaISO: fimDoDia.toISOString()
  }
}];

// Pega a data e hora em que o workflow está rodando
const agora = new Date();

// Calcula a data e hora para daqui a 60 minutos
// (60 minutos * 60 segundos * 1000 milissegundos)
const daquiUmaHora = new Date(agora.getTime() + 60 * 60 * 1000);

// Retorna as datas de início e fim no formato ISO, 
// que é o padrão que o Google Calendar espera.
return [{
  json: {
    agoraISO: agora.toISOString(),
    daquiUmaHoraISO: daquiUmaHora.toISOString()
  }
}];

// Pega a lista de etiquetas atuais que vem do item de entrada.
const etiquetasAtuais = items[0].json.etiquetas;

// Garante que 'etiquetasAtuais' é um array antes de tentar filtrar.
if (!Array.isArray(etiquetasAtuais)) {
  // Se não for um array, retorna um objeto com uma string vazia.
  return [{ json: { etiquetas_como_string: "" } }];
}

// Usa o método .filter() para criar uma nova lista com as tags que queremos manter.
const etiquetasFiltradas = etiquetasAtuais.filter(tag => tag !== "aguardando-resposta-lead");

// --- A MUDANÇA ESTÁ AQUI ---
// Junta os itens do array filtrado em uma única string, separados por vírgula.
// Exemplo: ["dba", "nicho-familia"] se torna "dba,nicho-familia"
const etiquetasComoString = etiquetasFiltradas.join(',');

// Retorna um novo objeto com a string de etiquetas.
return [{ json: { etiquetas_como_string: etiquetasComoString } }];
